import { useTranslation } from "react-i18next";
import { Gift, CheckCircle, Clock, Shield } from "lucide-react";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from "@/components/ui/dialog";
import { usePointsSettings } from "@/hooks/usePoints";

const PostPointsRulesDialog = () => {
  const { t } = useTranslation();
  const { data: settings } = usePointsSettings();

  // 从设置中提取值
  const postPoints = settings?.find(s => s.key === 'post_points')?.value || '5';
  const minLength = settings?.find(s => s.key === 'min_post_length')?.value || '10';
  const requireMedia = settings?.find(s => s.key === 'post_require_media')?.value === 'true';

  return (
    <Dialog>
      <DialogTrigger asChild>
        <button className="text-primary hover:underline text-sm whitespace-nowrap">
          {t("community.viewPointsRules", "查看详细规则")}
        </button>
      </DialogTrigger>
      <DialogContent className="max-w-md">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2">
            <Gift className="h-5 w-5 text-primary" />
            {t("community.pointsRulesTitle", "发帖积分规则")}
          </DialogTitle>
        </DialogHeader>
        <div className="space-y-4 pt-2">
          <p className="text-muted-foreground text-sm">
            {t("community.pointsRulesIntro", "通过发布社区帖子获得积分，具体规则如下：")}
          </p>
          <ul className="space-y-3">
            {/* 积分数量 */}
            <li className="flex items-start gap-2 text-sm">
              <CheckCircle className="h-4 w-4 text-green-500 mt-0.5 shrink-0" />
              <span>{t("community.rulePostPoints", { points: postPoints })}</span>
            </li>
            {/* 最小长度 */}
            <li className="flex items-start gap-2 text-sm">
              <CheckCircle className="h-4 w-4 text-green-500 mt-0.5 shrink-0" />
              <span>{t("community.ruleMinLength", { length: minLength })}</span>
            </li>
            {/* 媒体要求 */}
            {requireMedia && (
              <li className="flex items-start gap-2 text-sm">
                <CheckCircle className="h-4 w-4 text-green-500 mt-0.5 shrink-0" />
                <span>{t("community.ruleRequireMedia", "帖子必须包含至少一张图片或一个视频")}</span>
              </li>
            )}
            {/* 每日限制 */}
            <li className="flex items-start gap-2 text-sm">
              <Clock className="h-4 w-4 text-blue-500 mt-0.5 shrink-0" />
              <span>{t("community.ruleDailyLimit", "每天仅可通过发帖获得一次积分奖励")}</span>
            </li>
            {/* 审核要求 */}
            <li className="flex items-start gap-2 text-sm">
              <Shield className="h-4 w-4 text-purple-500 mt-0.5 shrink-0" />
              <span>{t("community.ruleModerationRequired", "帖子需通过审核后才能获得积分")}</span>
            </li>
          </ul>
        </div>
      </DialogContent>
    </Dialog>
  );
};

export default PostPointsRulesDialog;
