import { useCallback, useState } from "react";
import { useTranslation } from "react-i18next";
import { useNavigate, useLocation } from "react-router-dom";
import { Plus, LayoutGrid, List, Clock, Flame, LayoutList, FileText, Utensils } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Skeleton } from "@/components/ui/skeleton";
import PostGridCard from "@/components/community/PostGridCard";
import CreatePostDialog from "@/components/community/CreatePostDialog";
import { useCommunityPosts, useCanCreatePost, SortOption, PostTypeFilter } from "@/hooks/useCommunityPosts";
import { PullToRefresh } from "@/components/PullToRefresh";
import { useQueryClient } from "@tanstack/react-query";
import { useIsMobile } from "@/hooks/use-mobile";
import { useInfiniteScroll } from "@/hooks/useInfiniteScroll";
import { useAuth } from "@/contexts/AuthContext";
import { useLoginRequired } from "@/hooks/useLoginRequired";

// Skeleton for grid card
const PostGridSkeleton = () => (
  <div className="rounded-xl overflow-hidden bg-card border border-border/50">
    <Skeleton className="aspect-[4/5] w-full" />
    <div className="p-3 space-y-3">
      <div className="space-y-2">
        <Skeleton className="h-4 w-full" />
        <Skeleton className="h-4 w-3/4" />
      </div>
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-2">
          <Skeleton className="h-5 w-5 rounded-full" />
          <Skeleton className="h-3 w-16" />
        </div>
        <Skeleton className="h-4 w-10" />
      </div>
    </div>
  </div>
);

const Community = () => {
  const { t } = useTranslation();
  const queryClient = useQueryClient();
  const isMobile = useIsMobile();
  const { user } = useAuth();
  const { requireLogin } = useLoginRequired();
  const navigate = useNavigate();
  const location = useLocation();
  
  // Layout state: 'double' for 2 columns, 'single' for 1 column (mobile only)
  const [mobileLayout, setMobileLayout] = useState<'double' | 'single'>(() => {
    const saved = localStorage.getItem('community-mobile-layout');
    return (saved === 'single' ? 'single' : 'double') as 'double' | 'single';
  });

  // Sort state
  const [sortBy, setSortBy] = useState<SortOption>(() => {
    const saved = localStorage.getItem('community-sort');
    return (saved === 'popular' ? 'popular' : 'latest') as SortOption;
  });

  // Derive post type from URL path
  const postType: PostTypeFilter = location.pathname === '/community/posts' ? 'post'
    : location.pathname === '/community/recipes' ? 'recipe'
    : 'all';
  
  const { data: posts, isLoading } = useCommunityPosts({
    status: "approved",
    sortBy,
    postType
  });
  const { data: canPost } = useCanCreatePost();

  // Infinite scroll - only render 12 posts initially, load more on scroll
  const {
    displayedData: displayedPosts,
    hasMore,
    sentinelRef,
  } = useInfiniteScroll({
    data: posts,
    initialItemsPerPage: 12,
    incrementPerPage: 12,
  });
  
  // Pull-to-refresh handler - clears cache and forces fresh data
  const handleRefresh = useCallback(async () => {
    // Clear caches first to ensure fresh data
    queryClient.removeQueries({ queryKey: ['community-posts'] });
    queryClient.removeQueries({ queryKey: ['can-create-post'] });
    queryClient.removeQueries({ queryKey: ['has-posted-today'] });
    
    // Refetch with fresh data
    await Promise.all([
      queryClient.invalidateQueries({ queryKey: ['community-posts'] }),
      queryClient.invalidateQueries({ queryKey: ['can-create-post'] }),
      queryClient.invalidateQueries({ queryKey: ['has-posted-today'] }),
    ]);
  }, [queryClient]);

  const toggleMobileLayout = () => {
    const newLayout = mobileLayout === 'double' ? 'single' : 'double';
    setMobileLayout(newLayout);
    localStorage.setItem('community-mobile-layout', newLayout);
  };

  const handleSortChange = (value: string) => {
    const newSort = value as SortOption;
    setSortBy(newSort);
    localStorage.setItem('community-sort', newSort);
  };

  const handlePostTypeChange = (value: PostTypeFilter) => {
    const path = value === 'post' ? '/community/posts' : value === 'recipe' ? '/community/recipes' : '/community';
    navigate(path, { replace: true });
  };

  // Grid classes based on layout
  // Desktop (lg+): 4 columns, Tablet (md): 3 columns, Mobile: 1 or 2 based on toggle
  const getGridClasses = () => {
    if (isMobile) {
      return mobileLayout === 'single' 
        ? 'columns-1 gap-4' 
        : 'columns-2 gap-3';
    }
    // Tablet: 3 columns, Desktop: 4 columns
    return 'columns-3 lg:columns-4 gap-4';
  };

  return (
    <PullToRefresh onRefresh={handleRefresh}>
      <div className="min-h-screen bg-secondary/20 py-8 px-4 animate-fade-in">
        <div className="container mx-auto max-w-5xl">
          {/* Header */}
          <div className="flex items-center justify-between mb-4">
            <div>
              <h1 className="text-3xl sm:text-4xl mb-2 text-primary font-medium">
                {t("community.title", "社区")}
              </h1>
              <p className="text-muted-foreground text-base sm:text-lg">
                {t("community.description", "分享美食体验，发现更多精彩")}
              </p>
            </div>
            {canPost ? (
              <CreatePostDialog
                trigger={
                  <Button size="sm" className="gap-1.5">
                    <Plus className="h-4 w-4" />
                    <span className="hidden sm:inline">{t("community.createPost", "发布")}</span>
                  </Button>
                }
              />
            ) : !user ? (
              <Button size="sm" className="gap-1.5" onClick={() => requireLogin()}>
                <Plus className="h-4 w-4" />
                <span className="hidden sm:inline">{t("community.createPost", "发布")}</span>
              </Button>
            ) : null}
          </div>
          
          {/* Sort, Filter and Layout controls */}
          <div className="flex items-center gap-2 mb-4">
            {/* Sort tabs */}
            <div className="inline-flex h-9 items-center justify-center rounded-md bg-muted p-1 text-muted-foreground">
              <button
                onClick={() => handleSortChange('latest')}
                className={`inline-flex items-center justify-center whitespace-nowrap rounded-sm px-3 py-1.5 text-sm font-medium ring-offset-background transition-all focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 gap-1.5 ${
                  sortBy === 'latest' 
                    ? 'bg-background text-foreground shadow-sm' 
                    : ''
                }`}
              >
                <Clock className="h-3.5 w-3.5" />
                <span className="hidden sm:inline">{t("community.sortLatest", "最新")}</span>
              </button>
              <button
                onClick={() => handleSortChange('popular')}
                className={`inline-flex items-center justify-center whitespace-nowrap rounded-sm px-3 py-1.5 text-sm font-medium ring-offset-background transition-all focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 gap-1.5 ${
                  sortBy === 'popular' 
                    ? 'bg-background text-foreground shadow-sm' 
                    : ''
                }`}
              >
                <Flame className="h-3.5 w-3.5" />
                <span className="hidden sm:inline">{t("community.sortPopular", "热门")}</span>
              </button>
            </div>

            {/* Post type filter tabs */}
            <div className="inline-flex h-9 items-center justify-center rounded-md bg-muted p-1 text-muted-foreground">
              <button
                onClick={() => handlePostTypeChange('all')}
                className={`inline-flex items-center justify-center whitespace-nowrap rounded-sm px-3 py-1.5 text-sm font-medium ring-offset-background transition-all focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 gap-1.5 ${
                  postType === 'all' 
                    ? 'bg-background text-foreground shadow-sm' 
                    : ''
                }`}
              >
                <LayoutList className="h-3.5 w-3.5" />
                <span className="hidden sm:inline">{t("community.filterAll", "全部")}</span>
              </button>
              <button
                onClick={() => handlePostTypeChange('post')}
                className={`inline-flex items-center justify-center whitespace-nowrap rounded-sm px-3 py-1.5 text-sm font-medium ring-offset-background transition-all focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 gap-1.5 ${
                  postType === 'post' 
                    ? 'bg-background text-foreground shadow-sm' 
                    : ''
                }`}
              >
                <FileText className="h-3.5 w-3.5" />
                <span className="hidden sm:inline">{t("community.filterPost", "帖子")}</span>
              </button>
              <button
                onClick={() => handlePostTypeChange('recipe')}
                className={`inline-flex items-center justify-center whitespace-nowrap rounded-sm px-3 py-1.5 text-sm font-medium ring-offset-background transition-all focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 gap-1.5 ${
                  postType === 'recipe' 
                    ? 'bg-background text-foreground shadow-sm' 
                    : ''
                }`}
              >
                <Utensils className="h-3.5 w-3.5" />
                <span className="hidden sm:inline">{t("community.filterRecipe", "食谱")}</span>
              </button>
            </div>

            {/* Layout toggle - only show on mobile, always on the right */}
            {isMobile && (
              <button
                onClick={toggleMobileLayout}
                className="ml-auto inline-flex h-9 items-center justify-center whitespace-nowrap rounded-md bg-muted px-2.5 py-1.5 text-sm font-medium text-muted-foreground ring-offset-background transition-all focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2"
                title={mobileLayout === 'double' 
                  ? t("community.singleColumn", "单列布局") 
                  : t("community.doubleColumn", "双列布局")}
              >
                {mobileLayout === 'double' ? (
                  <List className="h-3.5 w-3.5" />
                ) : (
                  <LayoutGrid className="h-3.5 w-3.5" />
                )}
              </button>
            )}
          </div>

          {/* Content */}
          {isLoading ? (
            <div className={getGridClasses()}>
              {Array.from({ length: 8 }).map((_, i) => (
                <div key={i} className="break-inside-avoid mb-3 sm:mb-4">
                  <PostGridSkeleton />
                </div>
              ))}
            </div>
          ) : posts && posts.length > 0 ? (
            <>
              <div className={getGridClasses()}>
                {displayedPosts.map(post => (
                  <div key={post.id} className="break-inside-avoid mb-3 sm:mb-4">
                    <PostGridCard 
                      post={post} 
                      showAssociations={isMobile && mobileLayout === 'single'}
                    />
                  </div>
                ))}
              </div>
              {/* Infinite scroll sentinel */}
              {hasMore && (
                <div ref={sentinelRef} className="flex justify-center py-6">
                  <div className="h-8 w-8 animate-spin rounded-full border-2 border-primary border-t-transparent" />
                </div>
              )}
            </>
          ) : (
            <div className="flex flex-col items-center justify-center min-h-[60vh] text-center px-4">
              <div className="w-20 h-20 rounded-full bg-muted/50 flex items-center justify-center mb-4">
                <Plus className="w-8 h-8 text-muted-foreground/50" />
              </div>
              <p className="text-muted-foreground text-lg">
                {t("community.noPosts", "暂无帖子")}
              </p>
              {canPost && (
                <p className="mt-2 text-sm text-muted-foreground/70">
                  {t("community.beFirst", "成为第一个发帖的人吧！")}
                </p>
              )}
            </div>
          )}
        </div>
      </div>
    </PullToRefresh>
  );
};

export default Community;
