import { useState, useRef, useEffect } from "react";
import { useTranslation } from "react-i18next";
import { useLocation, useNavigate } from "react-router-dom";
import { Image, Video, X, Loader2, Calendar, MapPin, Gift, ArrowLeft } from "lucide-react";
import PostPointsRulesDialog from "./PostPointsRulesDialog";
import MultiRestaurantSelectDrawer from "./MultiRestaurantSelectDrawer";
import ActivitySelectDrawer from "./ActivitySelectDrawer";
import EmojiPicker from "./EmojiPicker";
import PostTypeSelector from "./PostTypeSelector";
import CreateRecipeWizard from "./recipe/CreateRecipeWizard";
import {
  Sheet,
  SheetContent,
  SheetTitle,
  SheetTrigger,
} from "@/components/ui/sheet";
import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea";
import { supabase } from "@/integrations/supabase/client";
import { useCreatePost, useMerchantRestaurant, useHasPostedToday } from "@/hooks/useCommunityPosts";
import { useActivities } from "@/hooks/useActivities";
import { useRestaurants } from "@/hooks/useRestaurants";
import { useUserRole } from "@/hooks/useUserRole";
import { useLocalizedContent } from "@/hooks/useLocalizedContent";
import { toast } from "sonner";
import * as VisuallyHidden from "@radix-ui/react-visually-hidden";

interface CreatePostDialogProps {
  trigger?: React.ReactNode;
}

const CreatePostDialog = ({ trigger }: CreatePostDialogProps) => {
  const { t } = useTranslation();
  const location = useLocation();
  const nav = useNavigate();
  const { getLocalizedField } = useLocalizedContent();
  const createPost = useCreatePost();
  const { data: activities } = useActivities();
  const { data: restaurants } = useRestaurants();
  const { role, isMerchant, isAdmin, isSupervisor } = useUserRole();
  const { data: merchantRestaurant } = useMerchantRestaurant();
  const { data: hasPostedToday, isLoading: checkingPost } = useHasPostedToday();

  const [open, setOpen] = useState(false);
  const [postType, setPostType] = useState<'selecting' | 'post' | 'recipe'>('selecting');

  // Auto-open when navigated back from AI recipe with state
  useEffect(() => {
    const state = location.state as any;
    if (state?.openCreatePost) {
      setOpen(true);
      // If pre-filled as post type (e.g. from video share), skip type selection
      if (state.prefillPostType === 'post') {
        setPostType('post');
        if (state.prefillContent) setContent(state.prefillContent);
        if (state.prefillVideoUrl) setVideoUrl(state.prefillVideoUrl);
        if (state.prefillAiRecipeSource) setAiRecipeSource(state.prefillAiRecipeSource);
      } else {
        setPostType('selecting');
      }
      // Clear the state so it doesn't re-trigger
      nav(location.pathname, { replace: true, state: {} });
    }
  }, [location.state]);
  const [content, setContent] = useState("");
  const [imageUrls, setImageUrls] = useState<string[]>([]);
  const [videoUrl, setVideoUrl] = useState<string | null>(null);
  const [activityId, setActivityId] = useState<string>("");
  const [restaurantIds, setRestaurantIds] = useState<string[]>([]);
  const [uploading, setUploading] = useState(false);
  const [restaurantOpen, setRestaurantOpen] = useState(false);
  const [activityOpen, setActivityOpen] = useState(false);
  const [showRestaurantError, setShowRestaurantError] = useState(false);
  const [aiRecipeSource, setAiRecipeSource] = useState<Record<string, any> | null>(null);

  const imageInputRef = useRef<HTMLInputElement>(null);
  const videoInputRef = useRef<HTMLInputElement>(null);

  // 普通用户 = 既不是商家、督导也不是管理员
  const isRegularUser = !isMerchant && !isSupervisor && !isAdmin;
  
  // 是否可以创建食谱（只有管理员、督导、商家可以）
  const canCreateRecipe = isAdmin || isSupervisor || isMerchant;

  // 商家自动设置餐厅
  useEffect(() => {
    if (isMerchant && merchantRestaurant && open) {
      setRestaurantIds([merchantRestaurant.id]);
    }
  }, [isMerchant, merchantRestaurant, open]);

  // 重置表单
  const resetForm = () => {
    // 所有用户都回到选择界面（普通用户看到"帖子"+"AI 食谱"，其他角色多一个"食谱"）
    setPostType('selecting');
    setContent("");
    setImageUrls([]);
    setVideoUrl(null);
    setActivityId("");
    setRestaurantIds([]);
    setRestaurantOpen(false);
    setActivityOpen(false);
    setShowRestaurantError(false);
    setAiRecipeSource(null);
  };

  // 初始化时设置正确的 postType
  // 普通用户也显示选择界面（含"发帖"和"AI 食谱"两个选项），不再跳过
  useEffect(() => {
    if (open) {
      setPostType('selecting');
    }
  }, [open]);

  const handleOpenChange = (newOpen: boolean) => {
    setOpen(newOpen);
    if (!newOpen) {
      resetForm();
    }
  };

  // Get active activities
  const activeActivities = activities?.filter((a) => a.status === "published") || [];

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;

    if (imageUrls.length + files.length > 9) {
      toast.error(t("community.maxImages", "最多上传9张图片"));
      return;
    }

    setUploading(true);
    try {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) throw new Error("Not authenticated");

      const uploadedUrls: string[] = [];

      for (const file of Array.from(files)) {
        const fileExt = file.name.split(".").pop();
        const fileName = `${user.id}/${Date.now()}-${Math.random().toString(36).substring(7)}.${fileExt}`;

        const { error: uploadError } = await supabase.storage
          .from("community-posts")
          .upload(fileName, file);

        if (uploadError) throw uploadError;

        const { data: { publicUrl } } = supabase.storage
          .from("community-posts")
          .getPublicUrl(fileName);

        uploadedUrls.push(publicUrl);
      }

      setImageUrls((prev) => [...prev, ...uploadedUrls]);
    } catch (error) {
      console.error("Upload error:", error);
      toast.error(t("common.uploadError", "上传失败"));
    } finally {
      setUploading(false);
      if (imageInputRef.current) {
        imageInputRef.current.value = "";
      }
    }
  };

  // Extract first frame from video file
  const extractVideoFirstFrame = (videoFile: File): Promise<Blob> => {
    return new Promise((resolve, reject) => {
      const video = document.createElement('video');
      const canvas = document.createElement('canvas');
      const ctx = canvas.getContext('2d');
      
      video.preload = 'auto';
      video.muted = true;
      video.playsInline = true;
      
      let hasResolved = false;
      
      const captureFrame = () => {
        if (hasResolved) return;
        if (video.videoWidth === 0 || video.videoHeight === 0) return;
        
        canvas.width = video.videoWidth;
        canvas.height = video.videoHeight;
        
        if (ctx) {
          ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
          canvas.toBlob((blob) => {
            if (blob && blob.size > 0) {
              hasResolved = true;
              video.pause();
              URL.revokeObjectURL(video.src);
              resolve(blob);
            } else {
              reject(new Error('Failed to create blob'));
            }
          }, 'image/jpeg', 0.85);
        }
      };
      
      video.onloadedmetadata = () => {
        canvas.width = video.videoWidth;
        canvas.height = video.videoHeight;
        video.currentTime = 0.1; // Jump to 0.1s to ensure frame is available
      };
      
      video.onseeked = () => {
        setTimeout(captureFrame, 100);
      };
      
      video.onerror = () => {
        URL.revokeObjectURL(video.src);
        reject(new Error('Failed to load video'));
      };
      
      // Timeout handling
      setTimeout(() => {
        if (!hasResolved) {
          URL.revokeObjectURL(video.src);
          reject(new Error('Timeout'));
        }
      }, 10000);
      
      video.src = URL.createObjectURL(videoFile);
      video.load();
    });
  };

  const handleVideoUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    // Check file size (max 100MB)
    if (file.size > 100 * 1024 * 1024) {
      toast.error(t("community.videoTooLarge", "视频不能超过100MB"));
      return;
    }

    setUploading(true);
    try {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) throw new Error("Not authenticated");

      // 1. Upload video
      const videoExt = file.name.split(".").pop();
      const videoFileName = `${user.id}/${Date.now()}.${videoExt}`;

      const { error: videoError } = await supabase.storage
        .from("community-posts")
        .upload(videoFileName, file);

      if (videoError) throw videoError;

      const { data: { publicUrl: videoPublicUrl } } = supabase.storage
        .from("community-posts")
        .getPublicUrl(videoFileName);

      setVideoUrl(videoPublicUrl);

      // 2. Extract and upload cover image
      try {
        toast.info(t("community.extractingCover", "正在提取视频封面..."));
        const coverBlob = await extractVideoFirstFrame(file);
        const coverFileName = `${user.id}/${Date.now()}-cover.jpg`;
        
        const { error: coverError } = await supabase.storage
          .from("community-posts")
          .upload(coverFileName, coverBlob);
        
        if (!coverError) {
          const { data: { publicUrl: coverUrl } } = supabase.storage
            .from("community-posts")
            .getPublicUrl(coverFileName);
          
          // Add cover image to the beginning of imageUrls
          setImageUrls(prev => [coverUrl, ...prev]);
          toast.success(t("community.coverExtracted", "封面已自动生成"));
        }
      } catch (coverError) {
        console.warn("Cover extraction failed:", coverError);
        // Cover extraction failure should not block video upload
      }

    } catch (error) {
      console.error("Upload error:", error);
      toast.error(t("common.uploadError", "上传失败"));
    } finally {
      setUploading(false);
      if (videoInputRef.current) {
        videoInputRef.current.value = "";
      }
    }
  };

  const removeImage = (index: number) => {
    setImageUrls((prev) => prev.filter((_, i) => i !== index));
  };

  const removeVideo = () => {
    setVideoUrl(null);
    // Remove auto-generated cover image (URL contains -cover.jpg)
    setImageUrls(prev => {
      if (prev.length > 0 && prev[0].includes('-cover.jpg')) {
        return prev.slice(1);
      }
      return prev;
    });
  };

  const handleSubmit = async () => {
    // 重置错误状态
    setShowRestaurantError(false);

    if (!content.trim()) {
      toast.error(t("community.contentRequired", "请输入内容"));
      return;
    }

    // 普通用户必须选择餐厅
    if (isRegularUser && restaurantIds.length === 0) {
      setShowRestaurantError(true);
      toast.error(t("community.restaurantRequired", "请选择餐厅"));
      return;
    }

    await createPost.mutateAsync({
      content,
      image_urls: imageUrls,
      video_url: videoUrl || undefined,
      activity_id: activityId || undefined,
      restaurant_ids: restaurantIds.length > 0 ? restaurantIds : undefined,
      ai_recipe_source: aiRecipeSource || undefined,
    });

    resetForm();
    setOpen(false);
  };


  // 获取商家餐厅名称
  const getMerchantRestaurantName = () => {
    if (!merchantRestaurant) return t("community.noRestaurant", "未关联餐厅");
    return getLocalizedField(merchantRestaurant, "name");
  };

  // Handle recipe creation success
  const handleRecipeSuccess = () => {
    resetForm();
    setOpen(false);
  };

  return (
    <Sheet open={open} onOpenChange={handleOpenChange}>
      <SheetTrigger asChild>
        {trigger || (
          <Button>{t("community.createPost", "发布帖子")}</Button>
        )}
      </SheetTrigger>
      <SheetContent 
        side="bottom" 
        className="h-full flex flex-col p-0 rounded-none border-0 [&>button]:hidden"
      >
        <VisuallyHidden.Root>
          <SheetTitle>{t("community.createPost", "发布帖子")}</SheetTitle>
        </VisuallyHidden.Root>

        {/* Post Type Selection */}
        {postType === 'selecting' && (
          <div className="h-full flex flex-col">
            <div className="flex items-center justify-between px-4 py-3 border-b bg-background shrink-0">
              <button
                type="button"
                onClick={() => setOpen(false)}
                className="p-1 -ml-1 hover:bg-muted rounded-md transition-colors"
              >
                <ArrowLeft className="h-5 w-5" />
              </button>
              <span className="font-medium">{t("community.create", "发布")}</span>
              <div className="w-6" />
            </div>
            <PostTypeSelector onSelect={setPostType} />
          </div>
        )}

        {/* Recipe Creation Wizard */}
        {postType === 'recipe' && (
          <CreateRecipeWizard 
            onClose={() => setPostType('selecting')} 
            onSuccess={handleRecipeSuccess}
          />
        )}

        {/* Regular Post Creation */}
        {postType === 'post' && (
          <>
          <input
            ref={imageInputRef}
            type="file"
            accept="image/*"
            multiple
            className="hidden"
            onChange={handleImageUpload}
          />
          <input
            ref={videoInputRef}
            type="file"
            accept="video/*"
            className="hidden"
            onChange={handleVideoUpload}
          />

        {/* Top Navigation - for regular post */}
        <div className="flex items-center justify-between px-4 py-3 border-b bg-background shrink-0">
          <button
            type="button"
            onClick={() => setPostType('selecting')}
            className="p-1 -ml-1 hover:bg-muted rounded-md transition-colors"
          >
            <ArrowLeft className="h-5 w-5" />
          </button>
          <Button
            size="sm"
            onClick={handleSubmit}
            disabled={createPost.isPending || !content.trim()}
            className="rounded-full px-6"
          >
            {createPost.isPending && <Loader2 className="h-4 w-4 mr-2 animate-spin" />}
            {t("community.publish", "发布")}
          </Button>
        </div>

        {/* Points Hint */}
        {!checkingPost && !hasPostedToday && (
          <div className="flex items-center justify-between gap-2 px-4 py-2 bg-primary/10 dark:bg-primary/20 border-b border-primary/30 dark:border-primary/40 text-sm text-primary dark:text-primary shrink-0">
            <div className="flex items-center gap-2">
              <Gift className="h-4 w-4 shrink-0" />
              <span>{t("community.dailyPointsHint", "每日发布首个帖子可获得5积分！")}</span>
            </div>
            <PostPointsRulesDialog />
          </div>
        )}

        {/* 横向两栏布局：左侧媒体，右侧文字 */}
        <div className="flex-1 flex flex-row overflow-hidden min-h-0">

          {/* 左侧：媒体上传区 */}
          <div className="w-[45%] border-r bg-muted/20 flex flex-col overflow-hidden shrink-0">
            <div className="flex-1 overflow-y-auto p-3 space-y-3">
              {/* 图片预览网格 */}
              {imageUrls.length > 0 && (
                <div className="grid grid-cols-2 gap-2">
                  {imageUrls.map((url, index) => (
                    <div key={index} className="relative aspect-square rounded-lg overflow-hidden bg-muted">
                      <img src={url} alt="" className="w-full h-full object-cover" />
                      <button
                        type="button"
                        onClick={() => removeImage(index)}
                        className="absolute top-1 right-1 p-1 bg-black/50 rounded-full text-white hover:bg-black/70"
                      >
                        <X className="h-3 w-3" />
                      </button>
                    </div>
                  ))}
                </div>
              )}

              {/* 视频预览 */}
              {videoUrl && (
                <div className="relative rounded-lg overflow-hidden">
                  <video src={videoUrl} controls className="w-full" preload="metadata" />
                  <button
                    type="button"
                    onClick={removeVideo}
                    className="absolute top-2 right-2 p-1 bg-black/50 rounded-full text-white hover:bg-black/70"
                  >
                    <X className="h-4 w-4" />
                  </button>
                </div>
              )}

              {/* 上传占位区（无媒体时） */}
              {imageUrls.length === 0 && !videoUrl && (
                <div
                  className="flex flex-col items-center justify-center gap-3 h-40 border-2 border-dashed border-muted-foreground/30 rounded-xl text-muted-foreground cursor-pointer hover:border-primary/50 hover:text-primary transition-colors"
                  onClick={() => imageInputRef.current?.click()}
                >
                  <Image className="h-8 w-8" />
                  <span className="text-sm">{t("community.addPhoto", "添加图片")}</span>
                </div>
              )}
            </div>

            {/* 媒体工具栏 */}
            <div className="flex items-center gap-4 px-3 py-3 border-t bg-background pb-[max(0.75rem,env(safe-area-inset-bottom))] shrink-0">
              <button
                type="button"
                onClick={() => imageInputRef.current?.click()}
                disabled={uploading || imageUrls.length >= 9}
                className="flex items-center gap-1.5 text-muted-foreground hover:text-foreground disabled:opacity-50 transition-colors"
              >
                <Image className="h-5 w-5" />
                <span className="text-xs">{t("community.photo", "照片")}</span>
              </button>

              <button
                type="button"
                onClick={() => videoInputRef.current?.click()}
                disabled={uploading || !!videoUrl}
                className="flex items-center gap-1.5 text-muted-foreground hover:text-foreground disabled:opacity-50 transition-colors"
              >
                <Video className="h-5 w-5" />
                <span className="text-xs">{t("community.video", "视频")}</span>
              </button>

              {uploading && <Loader2 className="h-4 w-4 animate-spin ml-auto text-muted-foreground" />}
            </div>
          </div>

          {/* 右侧：文字输入 + 关联信息 */}
          <div className="flex-1 flex flex-col overflow-hidden">
            {/* 文字输入区 */}
            <div className="flex-1 overflow-y-auto p-4">
              <Textarea
                value={content}
                onChange={(e) => setContent(e.target.value)}
                placeholder={t("community.contentPlaceholder", "分享你的想法...")}
                className="min-h-full h-full border-none shadow-none resize-none focus-visible:ring-0 p-0 text-base whitespace-pre-wrap"
              />
            </div>

            {/* 关联信息 + emoji */}
            <div className="px-4 py-2 border-t bg-background shrink-0 space-y-2 pb-[max(0.75rem,env(safe-area-inset-bottom))]">
              <div className="flex items-center gap-4 flex-wrap">
                {/* emoji */}
                <EmojiPicker onSelect={(emoji) => setContent((prev) => prev + emoji)} />

                {/* 餐厅选择 */}
                <div className={`flex items-center gap-2 ${showRestaurantError && isRegularUser && restaurantIds.length === 0 ? 'text-destructive' : ''}`}>
                  <MapPin className={`h-4 w-4 shrink-0 ${showRestaurantError && isRegularUser && restaurantIds.length === 0 ? 'text-destructive' : 'text-muted-foreground'}`} />
                  {isMerchant ? (
                    <span className="text-sm text-muted-foreground">{getMerchantRestaurantName()}</span>
                  ) : (
                    <MultiRestaurantSelectDrawer
                      open={restaurantOpen}
                      onOpenChange={(open) => {
                        setRestaurantOpen(open);
                        if (open) setShowRestaurantError(false);
                      }}
                      value={restaurantIds}
                      onSelect={(ids) => {
                        setRestaurantIds(ids);
                        setShowRestaurantError(false);
                      }}
                      restaurants={restaurants || []}
                      required={isRegularUser}
                    />
                  )}
                </div>

                {/* 活动选择 */}
                <div className="flex items-center gap-2">
                  <Calendar className="h-4 w-4 text-muted-foreground shrink-0" />
                  <ActivitySelectDrawer
                    open={activityOpen}
                    onOpenChange={setActivityOpen}
                    value={activityId}
                    onSelect={setActivityId}
                    activities={activeActivities}
                  />
                </div>
              </div>

              {/* 错误提示 */}
              {showRestaurantError && isRegularUser && restaurantIds.length === 0 && (
                <p className="text-xs text-destructive">
                  {t("community.restaurantRequired", "请选择餐厅")}
                </p>
              )}
            </div>
          </div>
        </div>
        </>
        )}
      </SheetContent>
    </Sheet>
  );
};

export default CreatePostDialog;
