import { useTranslation } from "react-i18next";
import { useNavigate } from "react-router-dom";
import { FileText, Utensils, Sparkles } from "lucide-react";
import { useUserRole } from "@/hooks/useUserRole";

interface PostTypeSelectorProps {
  onSelect: (type: 'post' | 'recipe') => void;
}

const PostTypeSelector = ({ onSelect }: PostTypeSelectorProps) => {
  const { t } = useTranslation();
  const navigate = useNavigate();
  const { isAdmin, isMerchant, isSupervisor } = useUserRole();

  const canCreateRecipeDirectly = isAdmin || isMerchant || isSupervisor;

  return (
    <div className="h-full flex flex-col items-center justify-center p-6">
      <h2 className="text-xl font-semibold mb-2">
        {t("community.selectPostType", "选择发布类型")}
      </h2>
      <p className="text-muted-foreground text-sm mb-8 text-center">
        {t("community.selectPostTypeDesc", "选择您想要发布的内容类型")}
      </p>

      <div className="flex flex-col gap-3 w-full max-w-sm">
        {/* Regular Post */}
        <button
          onClick={() => onSelect('post')}
          className="flex items-center gap-4 p-4 rounded-xl border-2 border-border hover:border-primary hover:bg-primary/5 transition-all duration-200 group text-left"
        >
          <div className="w-12 h-12 rounded-full bg-primary/10 flex items-center justify-center group-hover:bg-primary/20 transition-colors shrink-0">
            <FileText className="h-6 w-6 text-primary" />
          </div>
          <div>
            <h3 className="font-medium text-sm">
              {t("community.postType.post", "发布帖子")}
            </h3>
            <p className="text-xs text-muted-foreground mt-0.5">
              {t("community.postType.postDesc", "分享美食体验和想法")}
            </p>
          </div>
        </button>

        {/* Recipe - only for admins/merchants/supervisors */}
        {canCreateRecipeDirectly && (
          <button
            onClick={() => onSelect('recipe')}
            className="flex items-center gap-4 p-4 rounded-xl border-2 border-border hover:border-primary hover:bg-primary/5 transition-all duration-200 group text-left"
          >
            <div className="w-12 h-12 rounded-full bg-primary/10 flex items-center justify-center group-hover:bg-primary/20 transition-colors shrink-0">
              <Utensils className="h-6 w-6 text-primary" />
            </div>
            <div>
              <h3 className="font-medium text-sm">
                {t("community.postType.recipe", "发布食谱")}
              </h3>
              <p className="text-xs text-muted-foreground mt-0.5">
                {t("community.postType.recipeDesc", "分享烹饪教程和菜谱")}
              </p>
            </div>
          </button>
        )}

        {/* AI Recipe */}
        <button
          onClick={() => navigate('/ai-recipe', { state: { from: '/community' } })}
          className="flex items-center gap-4 p-4 rounded-xl border-2 border-border hover:border-primary hover:bg-primary/5 transition-all duration-200 group text-left"
        >
          <div className="w-12 h-12 rounded-full bg-primary/10 flex items-center justify-center group-hover:bg-primary/20 transition-colors shrink-0">
            <Sparkles className="h-6 w-6 text-primary" />
          </div>
          <div>
            <h3 className="font-medium text-sm">
              {t("community.postType.aiRecipe", "AI 食谱")}
            </h3>
            <p className="text-xs text-muted-foreground mt-0.5">
              {t("community.postType.aiRecipeDesc", "AI 识别食材并生成菜谱")}
            </p>
          </div>
        </button>
      </div>
    </div>
  );
};

export default PostTypeSelector;
